parameters.jsCode:
const meeting = $('Normalise Meeting Data').first().json;
let actions;
try { actions = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { actions = {}; }
return [{ json: { meeting_id: meeting.meeting_id, title: meeting.title, date: meeting.date, attendees: meeting.attendees, processed_at: new Date().toISOString(), ...actions } }];

parameters.message:
Meeting: {{ $json.title }}
Date: {{ $json.date }}
Attendees: {{ ($json.attendees||[]).join(', ') || 'Not specified' }}

SUMMARY
{{ $json.summary || 'No summary.' }}

DECISIONS ({{ ($json.decisions||[]).length }})
{{ ($json.decisions||[]).map(d => `• ${d.decision}${d.made_by ? ' — ' + d.made_by : ''}`).join('\n') || 'None recorded.' }}

ACTION ITEMS ({{ ($json.action_items||[]).length }})
{{ ($json.action_items||[]).map(a => `• [${a.priority.toUpperCase()}] ${a.action}${a.owner ? ' → ' + a.owner : ''}${a.deadline ? ' by ' + a.deadline : ''}`).join('\n') || 'None recorded.' }}

BLOCKERS ({{ ($json.blockers||[]).length }})
{{ ($json.blockers||[]).map(b => `⚠️ ${b.blocker}${b.owner ? ' (owner: ' + b.owner + ')' : ''}`).join('\n') || 'None.' }}

FOLLOW-UP QUESTIONS
{{ ($json.follow_up_questions||[]).map(q => `❓ ${q.question}${q.for ? ' — for ' + q.for : ''}`).join('\n') || 'None.' }}
